"use strict";(globalThis.webpackChunklearn_design_patterns_docs=globalThis.webpackChunklearn_design_patterns_docs||[]).push([[7703],{63030(t,n,e){e.r(n),e.d(n,{assets:()=>c,contentTitle:()=>o,default:()=>l,frontMatter:()=>d,metadata:()=>s,toc:()=>u});const s=JSON.parse('{"id":"component-collaboration/strategy/code","title":"\u6e90\u4ee3\u7801","description":"Strategy \u6a21\u5f0f\u7684\u5b8c\u6574\u5b9e\u73b0\u4ee3\u7801","source":"@site/docs/01-component-collaboration/strategy/code.md","sourceDirName":"01-component-collaboration/strategy","slug":"/component-collaboration/strategy/code","permalink":"/LearnDesignPatterns/docs/component-collaboration/strategy/code","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"sidebar_position":2,"title":"\u6e90\u4ee3\u7801","description":"Strategy \u6a21\u5f0f\u7684\u5b8c\u6574\u5b9e\u73b0\u4ee3\u7801"},"sidebar":"docs","previous":{"title":"\u7b56\u7565\u6a21\u5f0f\uff08Strategy\uff09","permalink":"/LearnDesignPatterns/docs/component-collaboration/strategy/"},"next":{"title":"\u89c2\u5bdf\u8005\u6a21\u5f0f\uff08Observer\uff09","permalink":"/LearnDesignPatterns/docs/component-collaboration/observer/"}}');var r=e(74848),a=e(28453);const d={sidebar_position:2,title:"\u6e90\u4ee3\u7801",description:"Strategy \u6a21\u5f0f\u7684\u5b8c\u6574\u5b9e\u73b0\u4ee3\u7801"},o="\u6e90\u4ee3\u7801",c={},u=[{value:"\u5934\u6587\u4ef6\uff08Strategy.h\uff09",id:"\u5934\u6587\u4ef6strategyh",level:2},{value:"\u5b9e\u73b0\u6587\u4ef6\uff08Strategy.cpp\uff09",id:"\u5b9e\u73b0\u6587\u4ef6strategycpp",level:2},{value:"\u6784\u5efa\u65b9\u5f0f",id:"\u6784\u5efa\u65b9\u5f0f",level:2}];function i(t){const n={admonition:"admonition",code:"code",h1:"h1",h2:"h2",header:"header",pre:"pre",...(0,a.R)(),...t.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(n.header,{children:(0,r.jsx)(n.h1,{id:"\u6e90\u4ee3\u7801",children:"\u6e90\u4ee3\u7801"})}),"\n",(0,r.jsx)(n.h2,{id:"\u5934\u6587\u4ef6strategyh",children:"\u5934\u6587\u4ef6\uff08Strategy.h\uff09"}),"\n",(0,r.jsx)(n.pre,{children:(0,r.jsx)(n.code,{className:"language-cpp",metastring:'title="Strategy.h" showLineNumbers',children:'#ifndef STRATEGY_H\n#define STRATEGY_H\n\n#include <string>\n#include <memory>\n#include <map>\n#include <functional>\n\n// =============================================================================\n// \u7b56\u7565\u6a21\u5f0f (Strategy Pattern) - \u7535\u5546\u652f\u4ed8\u7cfb\u7edf\n// =============================================================================\n// \u6838\u5fc3\u601d\u60f3\uff1a\u5b9a\u4e49\u4e00\u7cfb\u5217\u7b97\u6cd5\uff08\u652f\u4ed8\u65b9\u5f0f\uff09\uff0c\u628a\u5b83\u4eec\u5206\u522b\u5c01\u88c5\u8d77\u6765\uff0c\u5e76\u4f7f\u5b83\u4eec\u53ef\u4ee5\u4e92\u76f8\u66ff\u6362\u3002\n// \u7b56\u7565\u6a21\u5f0f\u8ba9\u7b97\u6cd5\u7684\u53d8\u5316\u72ec\u7acb\u4e8e\u4f7f\u7528\u7b97\u6cd5\u7684\u5ba2\u6237\u7aef\u3002\n// =============================================================================\n\n// \u652f\u4ed8\u8bf7\u6c42\u6570\u636e\nstruct PaymentRequest {\n    std::string orderId;\n    double amount;\n    std::string currency;\n    std::string customerEmail;\n\n    // \u652f\u4ed8\u65b9\u5f0f\u7279\u6709\u7684\u9644\u52a0\u4fe1\u606f\n    std::map<std::string, std::string> metadata;\n};\n\n// \u652f\u4ed8\u7ed3\u679c\nstruct PaymentResult {\n    bool success;\n    std::string transactionId;\n    std::string message;\n    double processedAmount;  // \u5b9e\u9645\u5904\u7406\u91d1\u989d\uff08\u53ef\u80fd\u542b\u624b\u7eed\u8d39\uff09\n    double fee;              // \u624b\u7eed\u8d39\n};\n\n// =============================================================================\n// \u7b56\u7565\u63a5\u53e3\uff1aPaymentStrategy\n// \u6240\u6709\u652f\u4ed8\u65b9\u5f0f\u90fd\u5b9e\u73b0\u6b64\u63a5\u53e3\uff0c\u4fdd\u8bc1\u53ef\u4ee5\u4e92\u76f8\u66ff\u6362\uff08\u91cc\u6c0f\u66ff\u6362\u539f\u5219\uff09\n// =============================================================================\nclass PaymentStrategy {\npublic:\n    virtual ~PaymentStrategy() = default;\n\n    // \u6267\u884c\u652f\u4ed8\n    virtual PaymentResult pay(const PaymentRequest& request) = 0;\n\n    // \u9a8c\u8bc1\u652f\u4ed8\u53c2\u6570\u662f\u5426\u6709\u6548\n    virtual bool validate(const PaymentRequest& request) const = 0;\n\n    // \u83b7\u53d6\u652f\u4ed8\u65b9\u5f0f\u540d\u79f0\uff08\u7528\u4e8e\u65e5\u5fd7\u548c\u663e\u793a\uff09\n    virtual std::string getName() const = 0;\n};\n\n// =============================================================================\n// \u5177\u4f53\u7b56\u7565\uff1a\u4fe1\u7528\u5361\u652f\u4ed8\n// =============================================================================\nclass CreditCardStrategy : public PaymentStrategy {\npublic:\n    CreditCardStrategy(const std::string& cardNumber,\n                       const std::string& holderName,\n                       const std::string& expiry,\n                       const std::string& cvv);\n\n    PaymentResult pay(const PaymentRequest& request) override;\n    bool validate(const PaymentRequest& request) const override;\n    std::string getName() const override { return "\u4fe1\u7528\u5361\u652f\u4ed8"; }\n\nprivate:\n    std::string cardNumber_;\n    std::string holderName_;\n    std::string expiry_;\n    std::string cvv_;\n\n    // \u4fe1\u7528\u5361\u624b\u7eed\u8d39\u7387\n    static constexpr double FEE_RATE = 0.02;  // 2%\n\n    // \u7b80\u5355\u7684 Luhn \u6821\u9a8c\uff08\u6a21\u62df\uff09\n    bool luhnCheck(const std::string& number) const;\n};\n\n// =============================================================================\n// \u5177\u4f53\u7b56\u7565\uff1a\u652f\u4ed8\u5b9d\u652f\u4ed8\n// =============================================================================\nclass AlipayStrategy : public PaymentStrategy {\npublic:\n    explicit AlipayStrategy(const std::string& accountId);\n\n    PaymentResult pay(const PaymentRequest& request) override;\n    bool validate(const PaymentRequest& request) const override;\n    std::string getName() const override { return "\u652f\u4ed8\u5b9d"; }\n\nprivate:\n    std::string accountId_;\n\n    // \u652f\u4ed8\u5b9d\u624b\u7eed\u8d39\u7387\n    static constexpr double FEE_RATE = 0.006;  // 0.6%\n    // \u5355\u7b14\u9650\u989d\n    static constexpr double MAX_AMOUNT = 50000.0;\n};\n\n// =============================================================================\n// \u5177\u4f53\u7b56\u7565\uff1a\u52a0\u5bc6\u8d27\u5e01\u652f\u4ed8\n// =============================================================================\nclass CryptoStrategy : public PaymentStrategy {\npublic:\n    CryptoStrategy(const std::string& walletAddress,\n                   const std::string& cryptoType = "BTC");\n\n    PaymentResult pay(const PaymentRequest& request) override;\n    bool validate(const PaymentRequest& request) const override;\n    std::string getName() const override { return "\u52a0\u5bc6\u8d27\u5e01 (" + cryptoType_ + ")"; }\n\nprivate:\n    std::string walletAddress_;\n    std::string cryptoType_;\n\n    // \u7f51\u7edc\u77ff\u5de5\u8d39\uff08\u56fa\u5b9a\u8d39\u7528\uff09\n    static constexpr double NETWORK_FEE = 5.0;\n\n    // \u6a21\u62df\u6c47\u7387\n    double getExchangeRate() const;\n};\n\n// =============================================================================\n// \u4e0a\u4e0b\u6587\uff1aPaymentProcessor\uff08\u8ba2\u5355\u652f\u4ed8\u5904\u7406\u5668\uff09\n// \u6301\u6709\u4e00\u4e2a\u7b56\u7565\u5bf9\u8c61\u7684\u5f15\u7528\uff0c\u5c06\u652f\u4ed8\u8bf7\u6c42\u59d4\u6258\u7ed9\u7b56\u7565\u5bf9\u8c61\u5904\u7406\u3002\n// \u8fd0\u884c\u65f6\u53ef\u4ee5\u52a8\u6001\u5207\u6362\u7b56\u7565\uff08\u8fd9\u662f\u7b56\u7565\u6a21\u5f0f\u4e0e\u6a21\u677f\u65b9\u6cd5\u7684\u5173\u952e\u533a\u522b\uff09\u3002\n// =============================================================================\nclass PaymentProcessor {\npublic:\n    explicit PaymentProcessor(std::unique_ptr<PaymentStrategy> strategy = nullptr);\n\n    // \u8fd0\u884c\u65f6\u5207\u6362\u652f\u4ed8\u7b56\u7565\uff08\u8fd9\u662f\u6a21\u5f0f\u7684\u6838\u5fc3\u80fd\u529b\uff09\n    void setStrategy(std::unique_ptr<PaymentStrategy> strategy);\n\n    // \u5904\u7406\u652f\u4ed8\uff1a\u59d4\u6258\u7ed9\u5f53\u524d\u7b56\u7565\n    PaymentResult processPayment(const PaymentRequest& request);\n\n    // \u83b7\u53d6\u5f53\u524d\u7b56\u7565\u540d\u79f0\n    std::string getCurrentStrategyName() const;\n\nprivate:\n    std::unique_ptr<PaymentStrategy> strategy_;\n};\n\n// =============================================================================\n// \u5de5\u5382\u51fd\u6570\uff1a\u6839\u636e\u652f\u4ed8\u65b9\u5f0f\u540d\u79f0\u521b\u5efa\u7b56\u7565\uff08\u7b80\u5316\u5ba2\u6237\u7aef\u4ee3\u7801\uff09\n// =============================================================================\nstd::unique_ptr<PaymentStrategy> createPaymentStrategy(\n    const std::string& type,\n    const std::map<std::string, std::string>& params);\n\n#endif // STRATEGY_H\n'})}),"\n",(0,r.jsx)(n.h2,{id:"\u5b9e\u73b0\u6587\u4ef6strategycpp",children:"\u5b9e\u73b0\u6587\u4ef6\uff08Strategy.cpp\uff09"}),"\n",(0,r.jsx)(n.pre,{children:(0,r.jsx)(n.code,{className:"language-cpp",metastring:'title="Strategy.cpp" showLineNumbers',children:'#include "Strategy.h"\n#include <iostream>\n#include <iomanip>\n#include <sstream>\n#include <ctime>\n#include <cstdlib>\n#include <random>\n\n// =============================================================================\n// \u8f85\u52a9\u51fd\u6570\n// =============================================================================\n\n// \u751f\u6210\u6a21\u62df\u7684\u4ea4\u6613 ID\nstatic std::string generateTransactionId(const std::string& prefix) {\n    static std::mt19937 rng(42);  // \u56fa\u5b9a\u79cd\u5b50\u4ee5\u83b7\u5f97\u53ef\u590d\u73b0\u7684\u8f93\u51fa\n    std::uniform_int_distribution<int> dist(10000, 99999);\n    return prefix + "-" + std::to_string(dist(rng));\n}\n\n// =============================================================================\n// CreditCardStrategy \u5b9e\u73b0\n// =============================================================================\n\nCreditCardStrategy::CreditCardStrategy(const std::string& cardNumber,\n                                       const std::string& holderName,\n                                       const std::string& expiry,\n                                       const std::string& cvv)\n    : cardNumber_(cardNumber)\n    , holderName_(holderName)\n    , expiry_(expiry)\n    , cvv_(cvv) {}\n\nPaymentResult CreditCardStrategy::pay(const PaymentRequest& request) {\n    std::cout << "  [\u4fe1\u7528\u5361] \u5904\u7406\u652f\u4ed8..." << std::endl;\n    std::cout << "  [\u4fe1\u7528\u5361] \u6301\u5361\u4eba: " << holderName_ << std::endl;\n    std::cout << "  [\u4fe1\u7528\u5361] \u5361\u53f7: ****-****-****-"\n              << cardNumber_.substr(cardNumber_.size() - 4) << std::endl;\n\n    // \u6a21\u62df\u8fde\u63a5\u94f6\u884c\u7f51\u5173\n    std::cout << "  [\u4fe1\u7528\u5361] \u8fde\u63a5\u94f6\u884c\u652f\u4ed8\u7f51\u5173..." << std::endl;\n    std::cout << "  [\u4fe1\u7528\u5361] 3D Secure \u9a8c\u8bc1\u901a\u8fc7" << std::endl;\n\n    double fee = request.amount * FEE_RATE;\n\n    PaymentResult result;\n    result.success = true;\n    result.transactionId = generateTransactionId("CC");\n    result.processedAmount = request.amount;\n    result.fee = fee;\n    result.message = "\u4fe1\u7528\u5361\u652f\u4ed8\u6210\u529f\uff0c\u624b\u7eed\u8d39 " + std::to_string(fee) + " " + request.currency;\n\n    return result;\n}\n\nbool CreditCardStrategy::validate(const PaymentRequest& request) const {\n    if (cardNumber_.empty() || cardNumber_.size() < 13) {\n        std::cout << "  [\u9a8c\u8bc1] \u4fe1\u7528\u5361\u53f7\u65e0\u6548" << std::endl;\n        return false;\n    }\n    if (cvv_.size() != 3 && cvv_.size() != 4) {\n        std::cout << "  [\u9a8c\u8bc1] CVV \u65e0\u6548" << std::endl;\n        return false;\n    }\n    if (request.amount <= 0) {\n        std::cout << "  [\u9a8c\u8bc1] \u91d1\u989d\u5fc5\u987b\u5927\u4e8e\u96f6" << std::endl;\n        return false;\n    }\n    return luhnCheck(cardNumber_);\n}\n\nbool CreditCardStrategy::luhnCheck(const std::string& number) const {\n    // \u7b80\u5316\u7684\u6821\u9a8c\uff1a\u4ec5\u68c0\u67e5\u662f\u5426\u5168\u4e3a\u6570\u5b57\n    for (char c : number) {\n        if (!std::isdigit(c)) return false;\n    }\n    return true;\n}\n\n// =============================================================================\n// AlipayStrategy \u5b9e\u73b0\n// =============================================================================\n\nAlipayStrategy::AlipayStrategy(const std::string& accountId)\n    : accountId_(accountId) {}\n\nPaymentResult AlipayStrategy::pay(const PaymentRequest& request) {\n    std::cout << "  [\u652f\u4ed8\u5b9d] \u5904\u7406\u652f\u4ed8..." << std::endl;\n    std::cout << "  [\u652f\u4ed8\u5b9d] \u8d26\u6237: " << accountId_ << std::endl;\n\n    // \u6a21\u62df\u652f\u4ed8\u5b9d\u652f\u4ed8\u6d41\u7a0b\n    std::cout << "  [\u652f\u4ed8\u5b9d] \u751f\u6210\u652f\u4ed8\u4e8c\u7ef4\u7801..." << std::endl;\n    std::cout << "  [\u652f\u4ed8\u5b9d] \u7528\u6237\u626b\u7801\u786e\u8ba4..." << std::endl;\n    std::cout << "  [\u652f\u4ed8\u5b9d] \u4f59\u989d\u6263\u6b3e\u6210\u529f" << std::endl;\n\n    double fee = request.amount * FEE_RATE;\n\n    PaymentResult result;\n    result.success = true;\n    result.transactionId = generateTransactionId("ALIPAY");\n    result.processedAmount = request.amount;\n    result.fee = fee;\n    result.message = "\u652f\u4ed8\u5b9d\u652f\u4ed8\u6210\u529f";\n\n    return result;\n}\n\nbool AlipayStrategy::validate(const PaymentRequest& request) const {\n    if (accountId_.empty()) {\n        std::cout << "  [\u9a8c\u8bc1] \u652f\u4ed8\u5b9d\u8d26\u6237 ID \u4e3a\u7a7a" << std::endl;\n        return false;\n    }\n    if (request.amount <= 0) {\n        std::cout << "  [\u9a8c\u8bc1] \u91d1\u989d\u5fc5\u987b\u5927\u4e8e\u96f6" << std::endl;\n        return false;\n    }\n    if (request.amount > MAX_AMOUNT) {\n        std::cout << "  [\u9a8c\u8bc1] \u8d85\u51fa\u652f\u4ed8\u5b9d\u5355\u7b14\u9650\u989d "\n                  << MAX_AMOUNT << " \u5143" << std::endl;\n        return false;\n    }\n    return true;\n}\n\n// =============================================================================\n// CryptoStrategy \u5b9e\u73b0\n// =============================================================================\n\nCryptoStrategy::CryptoStrategy(const std::string& walletAddress,\n                               const std::string& cryptoType)\n    : walletAddress_(walletAddress)\n    , cryptoType_(cryptoType) {}\n\nPaymentResult CryptoStrategy::pay(const PaymentRequest& request) {\n    std::cout << "  [\u52a0\u5bc6\u8d27\u5e01] \u5904\u7406 " << cryptoType_ << " \u652f\u4ed8..." << std::endl;\n    std::cout << "  [\u52a0\u5bc6\u8d27\u5e01] \u94b1\u5305\u5730\u5740: " << walletAddress_.substr(0, 10)\n              << "..." << std::endl;\n\n    double rate = getExchangeRate();\n    double cryptoAmount = request.amount / rate;\n\n    std::cout << std::fixed << std::setprecision(6);\n    std::cout << "  [\u52a0\u5bc6\u8d27\u5e01] \u6c47\u7387: 1 " << cryptoType_ << " = "\n              << rate << " " << request.currency << std::endl;\n    std::cout << "  [\u52a0\u5bc6\u8d27\u5e01] \u652f\u4ed8\u91d1\u989d: " << cryptoAmount\n              << " " << cryptoType_ << std::endl;\n\n    // \u6a21\u62df\u533a\u5757\u94fe\u786e\u8ba4\n    std::cout << "  [\u52a0\u5bc6\u8d27\u5e01] \u5e7f\u64ad\u4ea4\u6613\u5230\u533a\u5757\u94fe\u7f51\u7edc..." << std::endl;\n    std::cout << "  [\u52a0\u5bc6\u8d27\u5e01] \u7b49\u5f85\u786e\u8ba4 (3/6 \u533a\u5757\u786e\u8ba4)..." << std::endl;\n    std::cout << "  [\u52a0\u5bc6\u8d27\u5e01] \u4ea4\u6613\u786e\u8ba4\u5b8c\u6210" << std::endl;\n\n    PaymentResult result;\n    result.success = true;\n    result.transactionId = generateTransactionId("CRYPTO");\n    result.processedAmount = request.amount;\n    result.fee = NETWORK_FEE;\n    result.message = "\u52a0\u5bc6\u8d27\u5e01\u652f\u4ed8\u6210\u529f\uff0c\u652f\u4ed8 " + std::to_string(cryptoAmount)\n                   + " " + cryptoType_;\n\n    return result;\n}\n\nbool CryptoStrategy::validate(const PaymentRequest& request) const {\n    if (walletAddress_.empty() || walletAddress_.size() < 20) {\n        std::cout << "  [\u9a8c\u8bc1] \u94b1\u5305\u5730\u5740\u65e0\u6548" << std::endl;\n        return false;\n    }\n    if (request.amount <= NETWORK_FEE) {\n        std::cout << "  [\u9a8c\u8bc1] \u91d1\u989d\u8fc7\u5c0f\uff0c\u4e0d\u8db3\u4ee5\u8986\u76d6\u7f51\u7edc\u624b\u7eed\u8d39" << std::endl;\n        return false;\n    }\n    return true;\n}\n\ndouble CryptoStrategy::getExchangeRate() const {\n    // \u6a21\u62df\u6c47\u7387\uff08\u751f\u4ea7\u73af\u5883\u5e94\u8c03\u7528\u4ea4\u6613\u6240 API\uff09\n    if (cryptoType_ == "BTC") return 65000.0;\n    if (cryptoType_ == "ETH") return 3500.0;\n    return 1.0;\n}\n\n// =============================================================================\n// PaymentProcessor\uff08\u4e0a\u4e0b\u6587\uff09\u5b9e\u73b0\n// =============================================================================\n\nPaymentProcessor::PaymentProcessor(std::unique_ptr<PaymentStrategy> strategy)\n    : strategy_(std::move(strategy)) {}\n\n// \u8fd0\u884c\u65f6\u52a8\u6001\u5207\u6362\u7b56\u7565\u2014\u2014\u8fd9\u662f\u7b56\u7565\u6a21\u5f0f\u7684\u6838\u5fc3\u4ef7\u503c\nvoid PaymentProcessor::setStrategy(std::unique_ptr<PaymentStrategy> strategy) {\n    strategy_ = std::move(strategy);\n    std::cout << "[\u652f\u4ed8\u5904\u7406\u5668] \u5207\u6362\u652f\u4ed8\u65b9\u5f0f\u4e3a: "\n              << strategy_->getName() << std::endl;\n}\n\nPaymentResult PaymentProcessor::processPayment(const PaymentRequest& request) {\n    if (!strategy_) {\n        return {false, "", "\u672a\u8bbe\u7f6e\u652f\u4ed8\u65b9\u5f0f", 0.0, 0.0};\n    }\n\n    std::cout << "\\n--- \u5f00\u59cb\u5904\u7406\u8ba2\u5355 " << request.orderId << " ---" << std::endl;\n    std::cout << "\u91d1\u989d: " << std::fixed << std::setprecision(2)\n              << request.amount << " " << request.currency << std::endl;\n    std::cout << "\u652f\u4ed8\u65b9\u5f0f: " << strategy_->getName() << std::endl;\n\n    // Step 1: \u9a8c\u8bc1\u53c2\u6570\n    std::cout << "[\u652f\u4ed8\u5904\u7406\u5668] \u9a8c\u8bc1\u652f\u4ed8\u53c2\u6570..." << std::endl;\n    if (!strategy_->validate(request)) {\n        return {false, "", "\u652f\u4ed8\u53c2\u6570\u9a8c\u8bc1\u5931\u8d25", 0.0, 0.0};\n    }\n    std::cout << "[\u652f\u4ed8\u5904\u7406\u5668] \u9a8c\u8bc1\u901a\u8fc7" << std::endl;\n\n    // Step 2: \u59d4\u6258\u7ed9\u7b56\u7565\u6267\u884c\u652f\u4ed8\uff08\u7b56\u7565\u6a21\u5f0f\u7684\u6838\u5fc3\uff1a\u59d4\u6258\u800c\u975e\u7ee7\u627f\uff09\n    PaymentResult result = strategy_->pay(request);\n\n    // Step 3: \u8f93\u51fa\u7ed3\u679c\n    if (result.success) {\n        std::cout << "[\u652f\u4ed8\u5904\u7406\u5668] \u652f\u4ed8\u6210\u529f\uff01\u4ea4\u6613\u53f7: "\n                  << result.transactionId << std::endl;\n        std::cout << "[\u652f\u4ed8\u5904\u7406\u5668] \u624b\u7eed\u8d39: " << std::fixed << std::setprecision(2)\n                  << result.fee << " " << request.currency << std::endl;\n    } else {\n        std::cout << "[\u652f\u4ed8\u5904\u7406\u5668] \u652f\u4ed8\u5931\u8d25: " << result.message << std::endl;\n    }\n    std::cout << "--- \u8ba2\u5355\u5904\u7406\u5b8c\u6bd5 ---\\n" << std::endl;\n\n    return result;\n}\n\nstd::string PaymentProcessor::getCurrentStrategyName() const {\n    return strategy_ ? strategy_->getName() : "\u672a\u8bbe\u7f6e";\n}\n\n// =============================================================================\n// \u5de5\u5382\u51fd\u6570\uff1a\u6839\u636e\u7c7b\u578b\u5b57\u7b26\u4e32\u521b\u5efa\u7b56\u7565\u5bf9\u8c61\n// =============================================================================\nstd::unique_ptr<PaymentStrategy> createPaymentStrategy(\n    const std::string& type,\n    const std::map<std::string, std::string>& params) {\n\n    if (type == "credit_card") {\n        return std::make_unique<CreditCardStrategy>(\n            params.at("card_number"),\n            params.at("holder_name"),\n            params.at("expiry"),\n            params.at("cvv")\n        );\n    }\n    if (type == "alipay") {\n        return std::make_unique<AlipayStrategy>(params.at("account_id"));\n    }\n    if (type == "crypto") {\n        std::string cryptoType = "BTC";\n        auto it = params.find("crypto_type");\n        if (it != params.end()) cryptoType = it->second;\n        return std::make_unique<CryptoStrategy>(params.at("wallet_address"), cryptoType);\n    }\n\n    return nullptr;\n}\n\n// =============================================================================\n// \u4e3b\u51fd\u6570\uff1a\u6f14\u793a\u7b56\u7565\u6a21\u5f0f\n// =============================================================================\nint main() {\n    std::cout << "==================================================" << std::endl;\n    std::cout << "    \u7b56\u7565\u6a21\u5f0f (Strategy Pattern) \u6f14\u793a" << std::endl;\n    std::cout << "    \u573a\u666f\uff1a\u7535\u5546\u652f\u4ed8\u7cfb\u7edf" << std::endl;\n    std::cout << "==================================================" << std::endl;\n\n    // \u521b\u5efa\u652f\u4ed8\u5904\u7406\u5668\uff08\u4e0a\u4e0b\u6587\u5bf9\u8c61\uff09\n    PaymentProcessor processor;\n\n    // \u521b\u5efa\u4e00\u4e2a\u8ba2\u5355\u8bf7\u6c42\n    PaymentRequest order;\n    order.orderId = "ORD-2024-001";\n    order.amount = 1299.00;\n    order.currency = "CNY";\n    order.customerEmail = "customer@example.com";\n\n    // ========================================\n    // \u6f14\u793a1\uff1a\u4f7f\u7528\u4fe1\u7528\u5361\u652f\u4ed8\n    // ========================================\n    std::cout << "\\n\u3010\u6f14\u793a 1\u3011\u4fe1\u7528\u5361\u652f\u4ed8" << std::endl;\n    processor.setStrategy(std::make_unique<CreditCardStrategy>(\n        "6222021234567890", "\u5f20\u4e09", "12/26", "123"\n    ));\n    processor.processPayment(order);\n\n    // ========================================\n    // \u6f14\u793a2\uff1a\u8fd0\u884c\u65f6\u5207\u6362\u4e3a\u652f\u4ed8\u5b9d\u2014\u2014\u7b56\u7565\u6a21\u5f0f\u7684\u6838\u5fc3\u4ef7\u503c\n    // \u540c\u4e00\u4e2a\u8ba2\u5355\uff0c\u53ea\u9700\u5207\u6362\u7b56\u7565\u5bf9\u8c61\u5373\u53ef\u4f7f\u7528\u4e0d\u540c\u7684\u652f\u4ed8\u65b9\u5f0f\n    // ========================================\n    std::cout << "\u3010\u6f14\u793a 2\u3011\u8fd0\u884c\u65f6\u5207\u6362\u4e3a\u652f\u4ed8\u5b9d" << std::endl;\n    order.orderId = "ORD-2024-002";\n    order.amount = 688.50;\n    processor.setStrategy(std::make_unique<AlipayStrategy>("zhangsan@alipay.com"));\n    processor.processPayment(order);\n\n    // ========================================\n    // \u6f14\u793a3\uff1a\u5207\u6362\u4e3a\u52a0\u5bc6\u8d27\u5e01\u652f\u4ed8\n    // ========================================\n    std::cout << "\u3010\u6f14\u793a 3\u3011\u5207\u6362\u4e3a\u52a0\u5bc6\u8d27\u5e01 (ETH) \u652f\u4ed8" << std::endl;\n    order.orderId = "ORD-2024-003";\n    order.amount = 3500.00;\n    order.currency = "USD";\n    processor.setStrategy(std::make_unique<CryptoStrategy>(\n        "0x742d35Cc6634C0532925a3b844Bc9e7595f2bD38", "ETH"\n    ));\n    processor.processPayment(order);\n\n    // ========================================\n    // \u6f14\u793a4\uff1a\u4f7f\u7528\u5de5\u5382\u51fd\u6570\u521b\u5efa\u7b56\u7565\n    // ========================================\n    std::cout << "\u3010\u6f14\u793a 4\u3011\u4f7f\u7528\u5de5\u5382\u51fd\u6570\u521b\u5efa\u7b56\u7565" << std::endl;\n    order.orderId = "ORD-2024-004";\n    order.amount = 15000.00;\n    order.currency = "CNY";\n    auto strategy = createPaymentStrategy("credit_card", {\n        {"card_number", "6225881234567890"},\n        {"holder_name", "\u674e\u56db"},\n        {"expiry", "06/27"},\n        {"cvv", "456"}\n    });\n    processor.setStrategy(std::move(strategy));\n    processor.processPayment(order);\n\n    // ========================================\n    // \u6f14\u793a5\uff1a\u9a8c\u8bc1\u5931\u8d25\u7684\u60c5\u51b5\uff08\u652f\u4ed8\u5b9d\u8d85\u9650\u989d\uff09\n    // ========================================\n    std::cout << "\u3010\u6f14\u793a 5\u3011\u9a8c\u8bc1\u5931\u8d25 - \u652f\u4ed8\u5b9d\u8d85\u51fa\u9650\u989d" << std::endl;\n    order.orderId = "ORD-2024-005";\n    order.amount = 60000.00;  // \u8d85\u8fc7\u652f\u4ed8\u5b9d\u5355\u7b14\u9650\u989d 50000\n    processor.setStrategy(std::make_unique<AlipayStrategy>("lisi@alipay.com"));\n    PaymentResult failResult = processor.processPayment(order);\n    std::cout << "\u652f\u4ed8\u7ed3\u679c: " << (failResult.success ? "\u6210\u529f" : "\u5931\u8d25")\n              << " - " << failResult.message << std::endl;\n\n    // \u5173\u952e\u603b\u7ed3\n    std::cout << "\\n==================================================" << std::endl;\n    std::cout << "\u7b56\u7565\u6a21\u5f0f\u8981\u70b9\u603b\u7ed3\uff1a" << std::endl;\n    std::cout << "1. PaymentStrategy \u5b9a\u4e49\u7edf\u4e00\u7684\u652f\u4ed8\u63a5\u53e3" << std::endl;\n    std::cout << "2. \u5404\u652f\u4ed8\u65b9\u5f0f\u72ec\u7acb\u5c01\u88c5\uff0c\u4e92\u4e0d\u5f71\u54cd" << std::endl;\n    std::cout << "3. PaymentProcessor \u8fd0\u884c\u65f6\u52a8\u6001\u5207\u6362\u7b56\u7565" << std::endl;\n    std::cout << "4. \u65b0\u589e\u652f\u4ed8\u65b9\u5f0f\u53ea\u9700\u5b9e\u73b0\u63a5\u53e3\uff0c\u65e0\u9700\u4fee\u6539\u5df2\u6709\u4ee3\u7801" << std::endl;\n    std::cout << "5. \u7b56\u7565\u6a21\u5f0f\u7528\u7ec4\u5408\u66ff\u4ee3\u7ee7\u627f\uff0c\u66f4\u52a0\u7075\u6d3b" << std::endl;\n    std::cout << "==================================================" << std::endl;\n\n    return 0;\n}\n'})}),"\n",(0,r.jsx)(n.h2,{id:"\u6784\u5efa\u65b9\u5f0f",children:"\u6784\u5efa\u65b9\u5f0f"}),"\n",(0,r.jsx)(n.pre,{children:(0,r.jsx)(n.code,{className:"language-cmake",metastring:'title="CMakeLists.txt"',children:"add_executable(Pattern_Strategy Strategy.cpp Strategy.h)\ntarget_compile_features(Pattern_Strategy PRIVATE cxx_std_17)\n"})}),"\n",(0,r.jsx)(n.admonition,{title:"\u7f16\u8bd1\u8fd0\u884c",type:"tip",children:(0,r.jsx)(n.pre,{children:(0,r.jsx)(n.code,{className:"language-bash",children:"cd build\ncmake --build . --target Pattern_Strategy\n./Pattern_Strategy  # or .\\Release\\Pattern_Strategy.exe on Windows\n"})})})]})}function l(t={}){const{wrapper:n}={...(0,a.R)(),...t.components};return n?(0,r.jsx)(n,{...t,children:(0,r.jsx)(i,{...t})}):i(t)}},28453(t,n,e){e.d(n,{R:()=>d,x:()=>o});var s=e(96540);const r={},a=s.createContext(r);function d(t){const n=s.useContext(a);return s.useMemo(function(){return"function"==typeof t?t(n):{...n,...t}},[n,t])}function o(t){let n;return n=t.disableParentContext?"function"==typeof t.components?t.components(r):t.components||r:d(t.components),s.createElement(a.Provider,{value:n},t.children)}}}]);